 24→    ///
 25→    /// It is guaranteed that the destructor of the spawned task has finished
 26→    /// before task completion is observed via `JoinHandle` `await`,
 27→    /// [`JoinHandle::is_finished`] or [`AbortHandle::is_finished`].
 28→    ///
 29→    /// # Cancel safety
 30→    ///
 31→    /// The `&mut JoinHandle<T>` type is cancel safe. If it is used as the event
 32→    /// in a `tokio::select!` statement and some other branch completes first,
 33→    /// then it is guaranteed that the output of the task is not lost.
 34→    ///
 35→    /// If a `JoinHandle` is dropped, then the task continues running in the
 36→    /// background and its return value is lost.
 37→    ///
 38→    /// # Examples
 39→    ///
 40→    /// Creation from [`task::spawn`]:
 41→    ///
 42→    /// ```
 43→    /// use tokio::task;
 44→    ///
 45→    /// # async fn doc() {
 46→    /// let join_handle: task::JoinHandle<_> = task::spawn(async {
 47→    ///     // some work here
 48→    /// });
 49→    /// # }
 50→    /// ```
 51→    ///
 52→    /// Creation from [`task::spawn_blocking`]:
 53→    ///
 54→    /// ```
 55→    /// use tokio::task;
 56→    ///
 57→    /// # async fn doc() {
 58→    /// let join_handle: task::JoinHandle<_> = task::spawn_blocking(|| {
 59→    ///     // some blocking work here
 60→    /// });
 61→    /// # }
 62→    /// ```
 63→    ///
 64→    /// The generic parameter `T` in `JoinHandle<T>` is the return type of the spawned task.
 65→    /// If the return value is an `i32`, the join handle has type `JoinHandle<i32>`:
 66→    ///
 67→    /// ```
 68→    /// use tokio::task;
 69→    ///
 70→    /// # async fn doc() {
 71→    /// let join_handle: task::JoinHandle<i32> = task::spawn(async {
 72→    ///     5 + 3
 73→    /// });
 74→    /// # }
 75→    ///
 76→    /// ```
 77→    ///
 78→    /// If the task does not have a return value, the join handle has type `JoinHandle<()>`:
 79→    ///
 80→    /// ```
 81→    /// use tokio::task;
 82→    ///
 83→    /// # async fn doc() {
 84→    /// let join_handle: task::JoinHandle<()> = task::spawn(async {
 85→    ///     println!("I return nothing.");
 86→    /// });
 87→    /// # }
 88→    /// ```
 89→    ///
 90→    /// Note that `handle.await` doesn't give you the return type directly. It is wrapped in a
 91→    /// `Result` because panics in the spawned task are caught by Tokio. The `?` operator has
 92→    /// to be double chained to extract the returned value:
 93→    ///
 94→    /// ```
 95→    /// use tokio::task;
 96→    /// use std::io;
 97→    ///
 98→    /// # #[tokio::main(flavor = "current_thread")]
 99→    /// # async fn main() -> io::Result<()> {
100→    /// let join_handle: task::JoinHandle<Result<i32, io::Error>> = tokio::spawn(async {
101→    ///     Ok(5 + 3)
102→    /// });
103→    ///
104→    /// let result = join_handle.await??;
105→    /// assert_eq!(result, 8);
106→    /// Ok(())
107→    /// # }
108→    /// ```
109→    ///
110→    /// If the task panics, the error is a [`JoinError`] that contains the panic:
111→    ///
112→    /// ```
113→    /// # #[cfg(not(target_family = "wasm"))]
114→    /// # {
115→    /// use tokio::task;
116→    /// use std::io;
117→    /// use std::panic;
118→    ///
119→    /// #[tokio::main]
120→    /// async fn main() -> io::Result<()> {
121→    ///     let join_handle: task::JoinHandle<Result<i32, io::Error>> = tokio::spawn(async {
122→    ///         panic!("boom");
123→    ///     });
124→    ///
125→    ///     let err = join_handle.await.unwrap_err();
126→    ///     assert!(err.is_panic());
127→    ///     Ok(())
128→    /// }
129→    /// # }
130→    /// ```
131→    /// Child being detached and outliving its parent:
132→    ///
133→    /// ```no_run
134→    /// use tokio::task;
135→    /// use tokio::time;
136→    /// use std::time::Duration;
137→    ///
138→    /// # #[tokio::main(flavor = "current_thread")]
139→    /// # async fn main() {
140→    /// let original_task = task::spawn(async {
141→    ///     let _detached_task = task::spawn(async {
142→    ///         // Here we sleep to make sure that the first task returns before.
143→    ///         time::sleep(Duration::from_millis(10)).await;
144→    ///         // This will be called, even though the JoinHandle is dropped.
145→    ///         println!("♫ Still alive ♫");
146→    ///     });
147→    /// });
148→    ///
149→    /// original_task.await.expect("The task being joined has panicked");
150→    /// println!("Original task is joined.");

  1→//! This module has containers for storing the tasks spawned on a scheduler. The
  2→//! `OwnedTasks` container is thread-safe but can only store tasks that
  3→//! implement Send. The `LocalOwnedTasks` container is not thread safe, but can
  4→//! store non-Send tasks.
  5→//!
  6→//! The collections can be closed to prevent adding new tasks during shutdown of
  7→//! the scheduler with the collection.
  8→
  9→use crate::future::Future;
 10→use crate::loom::cell::UnsafeCell;
 11→use crate::runtime::task::{JoinHandle, LocalNotified, Notified, Schedule, SpawnLocation, Task};
 12→use crate::util::linked_list::{Link, LinkedList};
 13→use crate::util::sharded_list;
 14→
 15→use crate::loom::sync::atomic::{AtomicBool, Ordering};
 16→use std::marker::PhantomData;
 17→use std::num::NonZeroU64;
 18→
 19→// The id from the module below is used to verify whether a given task is stored
 20→// in this OwnedTasks, or some other task. The counter starts at one so we can
 21→// use `None` for tasks not owned by any list.
 22→//
 23→// The safety checks in this file can technically be violated if the counter is
 24→// overflown, but the checks are not supposed to ever fail unless there is a
 25→// bug in Tokio, so we accept that certain bugs would not be caught if the two
 26→// mixed up runtimes happen to have the same id.
 27→
 28→cfg_has_atomic_u64! {
 29→    use std::sync::atomic::AtomicU64;
 30→
 31→    static NEXT_OWNED_TASKS_ID: AtomicU64 = AtomicU64::new(1);
 32→
 33→    fn get_next_id() -> NonZeroU64 {
 34→        loop {
 35→            let id = NEXT_OWNED_TASKS_ID.fetch_add(1, Ordering::Relaxed);
 36→            if let Some(id) = NonZeroU64::new(id) {
 37→                return id;
 38→            }
 39→        }
 40→    }
 41→}
 42→
 43→cfg_not_has_atomic_u64! {
 44→    use std::sync::atomic::AtomicU32;
 45→
 46→    static NEXT_OWNED_TASKS_ID: AtomicU32 = AtomicU32::new(1);
 47→
 48→    fn get_next_id() -> NonZeroU64 {
 49→        loop {
 50→            let id = NEXT_OWNED_TASKS_ID.fetch_add(1, Ordering::Relaxed);
 51→            if let Some(id) = NonZeroU64::new(u64::from(id)) {
 52→                return id;
 53→            }
 54→        }
 55→    }
 56→}
 57→
 58→pub(crate) struct OwnedTasks<S: 'static> {
 59→    list: List<S>,
 60→    pub(crate) id: NonZeroU64,
 61→    closed: AtomicBool,
 62→}
 63→
 64→type List<S> = sharded_list::ShardedList<Task<S>, <Task<S> as Link>::Target>;
 65→
 66→pub(crate) struct LocalOwnedTasks<S: 'static> {
 67→    inner: UnsafeCell<OwnedTasksInner<S>>,
 68→    pub(crate) id: NonZeroU64,
 69→    _not_send_or_sync: PhantomData<*const ()>,
 70→}
 71→
 72→struct OwnedTasksInner<S: 'static> {
 73→    list: LinkedList<Task<S>, <Task<S> as Link>::Target>,
 74→    closed: bool,
 75→}
 76→
 77→impl<S: 'static> OwnedTasks<S> {
 78→    pub(crate) fn new(num_cores: usize) -> Self {
 79→        let shard_size = Self::gen_shared_list_size(num_cores);
 80→        Self {
 81→            list: List::new(shard_size),
 82→            closed: AtomicBool::new(false),
 83→            id: get_next_id(),
 84→        }
 85→    }
 86→
 87→    /// Binds the provided task to this `OwnedTasks` instance. This fails if the
 88→    /// `OwnedTasks` has been closed.
 89→    pub(crate) fn bind<T>(
 90→        &self,
 91→        task: T,
 92→        scheduler: S,
 93→        id: super::Id,
 94→        spawned_at: SpawnLocation,
 95→    ) -> (JoinHandle<T::Output>, Option<Notified<S>>)
 96→    where
 97→        S: Schedule,
 98→        T: Future + Send + 'static,
 99→        T::Output: Send + 'static,
100→    {
101→        let (task, notified, join) = super::new_task(task, scheduler, id, spawned_at);
102→        let notified = unsafe { self.bind_inner(task, notified) };
103→        (join, notified)
104→    }
105→
106→    /// Bind a task that isn't safe to transfer across thread boundaries.
107→    ///
108→    /// # Safety
109→    ///
110→    /// Only use this in `LocalRuntime` where the task cannot move
111→    pub(crate) unsafe fn bind_local<T>(
112→        &self,
113→        task: T,
114→        scheduler: S,
115→        id: super::Id,
116→        spawned_at: SpawnLocation,
117→    ) -> (JoinHandle<T::Output>, Option<Notified<S>>)
118→    where
119→        S: Schedule,
120→        T: Future + 'static,
121→        T::Output: 'static,
122→    {
123→        let (task, notified, join) = super::new_task(task, scheduler, id, spawned_at);
124→        let notified = unsafe { self.bind_inner(task, notified) };
125→        (join, notified)
126→    }
127→
128→    /// The part of `bind` that's the same for every type of future.
129→    unsafe fn bind_inner(&self, task: Task<S>, notified: Notified<S>) -> Option<Notified<S>>
130→    where
131→        S: Schedule,
132→    {
133→        unsafe {
134→            // safety: We just created the task, so we have exclusive access
135→            // to the field.
136→            task.header().set_owner_id(self.id);
137→        }
138→
139→        let shard = self.list.lock_shard(&task);
140→        // Check the closed flag in the lock for ensuring all that tasks
141→        // will shut down after the OwnedTasks has been closed.
142→        if self.closed.load(Ordering::Acquire) {
143→            drop(shard);
144→            task.shutdown();
145→            return None;
146→        }
147→        shard.push(task);
148→        Some(notified)
149→    }
150→

  1→use crate::runtime::task::{Header, RawTask, Schedule};
  2→
  3→use std::marker::PhantomData;
  4→use std::mem::ManuallyDrop;
  5→use std::ops;
  6→use std::ptr::NonNull;
  7→use std::task::{RawWaker, RawWakerVTable, Waker};
  8→
  9→pub(super) struct WakerRef<'a, S: 'static> {
 10→    waker: ManuallyDrop<Waker>,
 11→    _p: PhantomData<(&'a Header, S)>,
 12→}
 13→
 14→/// Returns a `WakerRef` which avoids having to preemptively increase the
 15→/// refcount if there is no need to do so.
 16→pub(super) fn waker_ref<S>(header: &NonNull<Header>) -> WakerRef<'_, S>
 17→where
 18→    S: Schedule,
 19→{
 20→    // `Waker::will_wake` uses the VTABLE pointer as part of the check. This
 21→    // means that `will_wake` will always return false when using the current
 22→    // task's waker. (discussion at rust-lang/rust#66281).
 23→    //
 24→    // To fix this, we use a single vtable. Since we pass in a reference at this
 25→    // point and not an *owned* waker, we must ensure that `drop` is never
 26→    // called on this waker instance. This is done by wrapping it with
 27→    // `ManuallyDrop` and then never calling drop.
 28→    let waker = unsafe { ManuallyDrop::new(Waker::from_raw(raw_waker(*header))) };
 29→
 30→    WakerRef {
 31→        waker,
 32→        _p: PhantomData,
 33→    }
 34→}
 35→
 36→impl<S> ops::Deref for WakerRef<'_, S> {
 37→    type Target = Waker;
 38→
 39→    fn deref(&self) -> &Waker {
 40→        &self.waker
 41→    }
 42→}
 43→
 44→cfg_trace! {
 45→    /// # Safety
 46→    ///
 47→    /// `$header` must be a valid pointer to a [`Header`].
 48→    macro_rules! trace {
 49→        ($header:expr, $op:expr) => {
 50→            if let Some(id) = Header::get_tracing_id(&$header) {
 51→                tracing::trace!(
 52→                    target: "tokio::task::waker",
 53→                    op = $op,
 54→                    task.id = id.into_u64(),
 55→                );
 56→            }
 57→        }
 58→    }
 59→}
 60→
 61→cfg_not_trace! {
 62→    macro_rules! trace {
 63→        ($header:expr, $op:expr) => {
 64→            // noop
 65→            let _ = &$header;
 66→        }
 67→    }
 68→}
 69→
 70→unsafe fn clone_waker(ptr: *const ()) -> RawWaker {
 71→    // Safety: `ptr` was created from a `Header` pointer in function `waker_ref`.
 72→    let header = unsafe { NonNull::new_unchecked(ptr as *mut Header) };
 73→    #[cfg_attr(not(all(tokio_unstable, feature = "tracing")), allow(unused_unsafe))]
 74→    unsafe {
 75→        trace!(header, "waker.clone");
 76→    }
 77→    unsafe { header.as_ref() }.state.ref_inc();
 78→    raw_waker(header)
 79→}
 80→
 81→unsafe fn drop_waker(ptr: *const ()) {
 82→    // Safety: `ptr` was created from a `Header` pointer in function `waker_ref`.
 83→    let ptr = unsafe { NonNull::new_unchecked(ptr as *mut Header) };
 84→    // TODO; replace to #[expect(unused_unsafe)] after bumping MSRV to 1.81.0.
 85→    #[cfg_attr(not(all(tokio_unstable, feature = "tracing")), allow(unused_unsafe))]
 86→    unsafe {
 87→        trace!(ptr, "waker.drop");
 88→    }
 89→    let raw = unsafe { RawTask::from_raw(ptr) };
 90→    raw.drop_reference();
 91→}
 92→
 93→unsafe fn wake_by_val(ptr: *const ()) {
 94→    // Safety: `ptr` was created from a `Header` pointer in function `waker_ref`.
 95→    let ptr = unsafe { NonNull::new_unchecked(ptr as *mut Header) };
 96→    // TODO; replace to #[expect(unused_unsafe)] after bumping MSRV to 1.81.0.
 97→    #[cfg_attr(not(all(tokio_unstable, feature = "tracing")), allow(unused_unsafe))]
 98→    unsafe {
 99→        trace!(ptr, "waker.wake");
100→    }
101→    let raw = unsafe { RawTask::from_raw(ptr) };
102→    raw.wake_by_val();
103→}
104→
105→// Wake without consuming the waker
106→unsafe fn wake_by_ref(ptr: *const ()) {
107→    // Safety: `ptr` was created from a `Header` pointer in function `waker_ref`.
108→    let ptr = unsafe { NonNull::new_unchecked(ptr as *mut Header) };
109→    // TODO; replace to #[expect(unused_unsafe)] after bumping MSRV to 1.81.0.
110→    #[cfg_attr(not(all(tokio_unstable, feature = "tracing")), allow(unused_unsafe))]
111→    unsafe {
112→        trace!(ptr, "waker.wake_by_ref");
113→    }
114→    let raw = unsafe { RawTask::from_raw(ptr) };
115→    raw.wake_by_ref();
116→}
117→
118→static WAKER_VTABLE: RawWakerVTable =
119→    RawWakerVTable::new(clone_waker, wake_by_val, wake_by_ref, drop_waker);
120→
121→fn raw_waker(header: NonNull<Header>) -> RawWaker {
122→    let ptr = header.as_ptr() as *const ();
123→    RawWaker::new(ptr, &WAKER_VTABLE)
124→}
125→

