126→    /// Returns a [task ID] that identifies the task which errored relative to
127→    /// other currently spawned tasks.
128→    ///
129→    /// [task ID]: crate::task::Id
130→    pub fn id(&self) -> Id {
131→        self.id
132→    }
133→}
