311→        assert_eq!(task_id, self.id);
312→
313→        self.with_inner(|inner|
314→            // safety: We just checked that the provided task is not in some
315→            // other linked list.
316→            unsafe { inner.list.remove(task.header_ptr()) })
317→    }
